import React, { useState, useEffect } from 'react';

export default function StatusTracker({ appTheme }) {
    const [applications] = useState([
        {
            id_lamaran: 'APP-001',
            title: 'Fullstack Developer',
            company: 'PasukanYerusSolo',
            applied_date: '2026-05-28',
            status: 'Diproses',
            pesan_hrd: 'Berkas CV Anda sedang ditinjau.'
        }
    ]);

    const colors = {
        bg: '#0c0a09',
        card: '#171717',
        border: '#262626',
        textMain: '#ffffff',
        textMuted: '#a3a3a3',
        accent: '#f59e0b'
    };

    return (
        <div style={{ 
            width: '100%', 
            maxWidth: '900px', // Membatasi lebar agar tidak terlalu panjang
            margin: '0 auto', 
            padding: '24px' 
        }}>
            <h2 style={{ color: colors.textMain, marginBottom: '24px' }}>Status Lamaran Saya</h2>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                {applications.map((app) => {
                    const isDiproses = app.status === 'Diproses';
                    return (
                        <div key={app.id_lamaran} style={{ 
                            background: colors.card, 
                            border: `1px solid ${colors.border}`, 
                            borderRadius: '12px', 
                            padding: '20px', 
                            display: 'flex', 
                            justifyContent: 'space-between', 
                            alignItems: 'center' 
                        }}>
                            <div>
                                <h3 style={{ margin: '0 0 4px 0', color: colors.textMain }}>{app.title}</h3>
                                <p style={{ margin: 0, color: colors.accent, fontSize: '14px', fontWeight: '600' }}>{app.company}</p>
                                <p style={{ margin: '8px 0 0 0', color: colors.textMuted, fontSize: '12px' }}>Diterapkan pada: {app.applied_date}</p>
                            </div>

                            <div style={{ 
                                padding: '8px 16px', 
                                borderRadius: '8px', 
                                background: isDiproses ? '#431407' : '#064e3b', 
                                color: isDiproses ? '#f59e0b' : '#34d399', 
                                fontWeight: '700', 
                                fontSize: '13px' 
                            }}>
                                {app.status}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
}
